#include <stdio.h>

int main() {
    int luckNumbers[] = {7, 13, 21, 99};

    printf("First number is %d\n", luckNumbers[0]); // Prints 7

    // Change the second number (Index 1!)
    luckNumbers[1] = 14;
    printf("Changed to %d\n", luckNumbers[1]); // Prints 14
    return 0;
}
